* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: Arial, sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    text-align: center;
    background: white;
    padding: 40px;
    border-radius: 10px;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.3);
}

h1 {
    color: #333;
    margin-bottom: 30px;
    font-size: 2.5em;
}

.game-info {
    margin-bottom: 20px;
}

#status {
    font-size: 1.3em;
    color: #667eea;
    font-weight: bold;
    min-height: 1.5em;
}

.board {
    display: grid;
    grid-template-columns: repeat(3, 100px);
    grid-gap: 10px;
    margin: 30px auto;
    background: #333;
    padding: 10px;
    border-radius: 5px;
    width: fit-content;
}

.cell {
    width: 100px;
    height: 100px;
    background: white;
    border: none;
    font-size: 2em;
    font-weight: bold;
    cursor: pointer;
    border-radius: 5px;
    display: flex;
    justify-content: center;
    align-items: center;
    transition: all 0.3s ease;
    color: #333;
}

.cell:hover:not([data-disabled="true"]) {
    background: #f0f0f0;
    transform: scale(1.05);
    box-shadow: 0 5px 15px rgba(0, 0, 0, 0.2);
}

.cell[data-disabled="true"] {
    cursor: not-allowed;
}

.cell.x {
    color: #667eea;
}

.cell.o {
    color: #764ba2;
}

.cell.winner {
    background: #FFD700;
    box-shadow: 0 0 10px rgba(255, 215, 0, 0.5);
}

.reset-btn {
    padding: 12px 30px;
    font-size: 1.1em;
    background: #667eea;
    color: white;
    border: none;
    border-radius: 5px;
    cursor: pointer;
    transition: all 0.3s ease;
    font-weight: bold;
}

.reset-btn:hover {
    background: #764ba2;
    transform: scale(1.05);
    box-shadow: 0 5px 15px rgba(0, 0, 0, 0.2);
}

.reset-btn:active {
    transform: scale(0.98);
}

