input.content:
class TicTacToe {
    constructor() {
        this.board = Array(9).fill(null);
        this.currentPlayer = 'X';
        this.gameOver = false;
        this.winner = null;

        this.cells = document.querySelectorAll('.cell');
        this.statusDisplay = document.getElementById('status');
        this.resetBtn = document.getElementById('resetBtn');

        this.initializeEventListeners();
    }

    initializeEventListeners() {
        this.cells.forEach((cell, index) => {
            cell.addEventListener('click', () => this.handleCellClick(index));
        });
        this.resetBtn.addEventListener('click', () => this.reset());
    }

    handleCellClick(index) {
        // Ignore click if cell is occupied or game is over
        if (this.board[index] !== null || this.gameOver) {
            return;
        }

        // Place the current player's mark
        this.board[index] = this.currentPlayer;
        this.renderCell(index);

        // Check for win or draw
        if (this.checkWin()) {
            this.winner = this.currentPlayer;
            this.gameOver = true;
            this.statusDisplay.textContent = `Player ${this.winner} Wins!`;
            this.highlightWinningCells();
            return;
        }

        if (this.checkDraw()) {
            this.gameOver = true;
            this.statusDisplay.textContent = "It's a Draw!";
            return;
        }

        // Switch to the other player
        this.currentPlayer = this.currentPlayer === 'X' ? 'O' : 'X';
        this.statusDisplay.textContent = `Player ${this.currentPlayer}'s Turn`;
    }

    renderCell(index) {
        const cell = this.cells[index];
        cell.textContent = this.board[index];
        cell.classList.add(this.board[index].toLowerCase());
        cell.setAttribute('data-disabled', 'true');
    }

    checkWin() {
        const winningCombinations = [
            [0, 1, 2],
            [3, 4, 5],
            [6, 7, 8],
            [0, 3, 6],
            [1, 4, 7],
            [2, 5, 8],
            [0, 4, 8],
            [2, 4, 6]
        ];

        return winningCombinations.some(combination => {
            const [a, b, c] = combination;
            if (
                this.board[a] !== null &&
                this.board[a] === this.board[b] &&
                this.board[a] === this.board[c]
            ) {
                this.winningCombination = combination;
                return true;
            }
        });
    }

    checkDraw() {
        return this.board.every(cell => cell !== null);
    }

    highlightWinningCells() {
        if (this.winningCombination) {
            this.winningCombination.forEach(index => {
                this.cells[index].classList.add('winner');
            });
        }
    }

    reset() {
        this.board = Array(9).fill(null);
        this.currentPlayer = 'X';
        this.gameOver = false;
        this.winner = null;
        this.winningCombination = null;

        this.cells.forEach(cell => {
            cell.textContent = '';
            cell.classList.remove('x', 'o', 'winner');
            cell.setAttribute('data-disabled', 'false');
        });

        this.statusDisplay.textContent = `Player ${this.currentPlayer}'s Turn`;
    }
}

// Initialize the game when DOM is ready
document.addEventListener('DOMContentLoaded', () => {
    new TicTacToe();
});

