// Simple assertion helpers
function assert(condition, message) {
    if (condition) {
        console.log('✓ PASS:', message);
    } else {
        console.log('✗ FAIL:', message);
        process.exit(1);
    }
}

function assertEqual(actual, expected, message) {
    if (actual === expected) {
        console.log('✓ PASS:', message);
    } else {
        console.log(`✗ FAIL: ${message} (expected: ${expected}, got: ${actual})`);
        process.exit(1);
    }
}

// Extract game logic from the browser version
class TicTacToe {
    constructor() {
        this.board = Array(9).fill(null);
        this.currentPlayer = 'X';
        this.gameOver = false;
        this.winner = null;
        this.winningCombination = null;
    }

    handleMove(index) {
        if (this.board[index] !== null || this.gameOver) {
            return false;
        }

        this.board[index] = this.currentPlayer;

        if (this.checkWin()) {
            this.winner = this.currentPlayer;
            this.gameOver = true;
            return true;
        }

        if (this.checkDraw()) {
            this.gameOver = true;
            return true;
        }

        this.currentPlayer = this.currentPlayer === 'X' ? 'O' : 'X';
        return true;
    }

    checkWin() {
        const winningCombinations = [
            [0, 1, 2],
            [3, 4, 5],
            [6, 7, 8],
            [0, 3, 6],
            [1, 4, 7],
            [2, 5, 8],
            [0, 4, 8],
            [2, 4, 6]
        ];

        return winningCombinations.some(combination => {
            const [a, b, c] = combination;
            if (
                this.board[a] !== null &&
                this.board[a] === this.board[b] &&
                this.board[a] === this.board[c]
            ) {
                this.winningCombination = combination;
                return true;
            }
        });
    }

    checkDraw() {
        return this.board.every(cell => cell !== null);
    }

    reset() {
        this.board = Array(9).fill(null);
        this.currentPlayer = 'X';
        this.gameOver = false;
        this.winner = null;
        this.winningCombination = null;
    }
}

// Test Suite
console.log('\n=== TIC TAC TOE TEST SUITE ===\n');

// Test 1: Win Detection - Horizontal Rows
console.log('--- Testing Row Wins ---');
let game = new TicTacToe();
game.board = ['X', 'X', 'X', 'O', 'O', null, null, null, null];
assert(game.checkWin(), 'Row 0 (0,1,2): X wins');

game = new TicTacToe();
game.board = [null, null, null, 'O', 'O', 'O', 'X', 'X', null];
assert(game.checkWin(), 'Row 1 (3,4,5): O wins');

game = new TicTacToe();
game.board = [null, null, null, null, null, null, 'X', 'X', 'X'];
assert(game.checkWin(), 'Row 2 (6,7,8): X wins');

// Test 2: Win Detection - Vertical Columns
console.log('\n--- Testing Column Wins ---');
game = new TicTacToe();
game.board = ['X', 'O', null, 'X', 'O', null, 'X', null, null];
assert(game.checkWin(), 'Column 0 (0,3,6): X wins');

game = new TicTacToe();
game.board = [null, 'O', null, null, 'O', null, null, 'O', 'X'];
assert(game.checkWin(), 'Column 1 (1,4,7): O wins');

game = new TicTacToe();
game.board = [null, null, 'X', 'O', 'O', 'X', null, null, 'X'];
assert(game.checkWin(), 'Column 2 (2,5,8): X wins');

// Test 3: Win Detection - Diagonals
console.log('\n--- Testing Diagonal Wins ---');
game = new TicTacToe();
game.board = ['X', 'O', null, 'O', 'X', null, null, null, 'X'];
assert(game.checkWin(), 'Diagonal (0,4,8): X wins');
assertEqual(game.winningCombination.join(','), '0,4,8', 'Winning combination correctly identified');

game = new TicTacToe();
game.board = [null, null, 'O', 'X', 'O', null, 'X', null, null];
assert(game.checkWin(), 'Diagonal (2,4,6): O wins');
assertEqual(game.winningCombination.join(','), '2,4,6', 'Winning combination correctly identified');

// Test 4: Draw Detection
console.log('\n--- Testing Draw Detection ---');
game = new TicTacToe();
game.board = ['X', 'X', 'O', 'O', 'O', 'X', 'X', 'X', 'O'];
assert(game.checkDraw(), 'Filled board with no winner is a draw');

game = new TicTacToe();
game.board = ['X', 'O', null, 'O', 'X', 'X', 'O', 'X', 'X'];
assert(!game.checkDraw(), 'Board with empty cell is not a draw');

// Test 5: Turn Switching
console.log('\n--- Testing Turn Switching ---');
game = new TicTacToe();
assertEqual(game.currentPlayer, 'X', 'Game starts with X');

game.handleMove(0);
assertEqual(game.currentPlayer, 'O', 'After X moves, O should play');

game.handleMove(1);
assertEqual(game.currentPlayer, 'X', 'After O moves, X should play');

game.handleMove(2);
assertEqual(game.currentPlayer, 'O', 'Turn switching continues correctly');

// Test 6: Prevent Double Clicks
console.log('\n--- Testing Double Click Prevention ---');
game = new TicTacToe();
const result1 = game.handleMove(4);
const result2 = game.handleMove(4);
assert(result1 === true, 'First move on cell 4 succeeds');
assert(result2 === false, 'Second move on same cell fails');
assertEqual(game.board[4], 'X', 'Cell 4 contains only first player move');

// Test 7: Prevent Moves After Game Over
console.log('\n--- Testing Game Over Prevention ---');
game = new TicTacToe();
game.board = ['X', 'X', 'X', 'O', 'O', null, null, null, null];
game.checkWin();
game.winner = 'X';
game.gameOver = true;

const moveAfterWin = game.handleMove(5);
assert(moveAfterWin === false, 'Cannot move after game is won');

// Test 8: Reset Functionality
console.log('\n--- Testing Reset Functionality ---');
game = new TicTacToe();
game.board = ['X', 'O', 'X', 'O', 'X', 'O', 'O', 'X', 'X'];
game.currentPlayer = 'O';
game.gameOver = true;
game.winner = 'X';

game.reset();
assertEqual(game.board.filter(cell => cell !== null).length, 0, 'Board is cleared');
assertEqual(game.currentPlayer, 'X', 'Player reset to X');
assertEqual(game.gameOver, false, 'Game over flag reset');
assertEqual(game.winner, null, 'Winner reset to null');
assert(game.handleMove(0), 'Can make moves after reset');

// Test 9: Complete Game Flow
console.log('\n--- Testing Complete Game Flow (X Wins) ---');
game = new TicTacToe();
// X takes center
game.handleMove(4);
assertEqual(game.currentPlayer, 'O', 'After X moves, turn is O');

// O takes corner
game.handleMove(0);
assertEqual(game.currentPlayer, 'X', 'After O moves, turn is X');

// X takes opposite corner
game.handleMove(8);
assertEqual(game.currentPlayer, 'O', 'Turn is O');

// O blocks diagonal
game.handleMove(2);
assertEqual(game.currentPlayer, 'X', 'Turn is X');

// X wins with middle column
game.handleMove(1);
assert(game.gameOver === true, 'Game ends after winning move');
assertEqual(game.winner, 'X', 'X is the winner');

// Test 10: All cells tested individually
console.log('\n--- Testing All Grid Positions ---');
game = new TicTacToe();
for (let i = 0; i < 9; i++) {
    game.reset();
    const result = game.handleMove(i);
    assertEqual(game.board[i], 'X', `Cell ${i} accepts move`);
    assert(result === true, `Move to cell ${i} returns true`);
}

console.log('\n=== ALL TESTS PASSED ✓ ===\n');

